using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using System;
using System.IO;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using System.Security.Cryptography.Xml;
using System.Text;
using System.Web;
using System.Xml;

namespace SamlGenerator.Pages
{
    public class IndexModel : PageModel
    {
        public string SamlRequestXml { get; set; }
        public string ErrorMessage { get; set; }

        // Configuration for SAML Request
        private const string IssuerEntityId = "http://localhost:5000/sp"; // Your Service Provider's Entity ID
        private const string DestinationUrl = "http://localhost:5001/saml/sso"; // IdP's SSO URL
        private const string AssertionConsumerServiceUrl = "http://localhost:5000/saml/acs"; // Your SP's ACS URL
        private const string ProtocolBinding = "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"; // Or HTTP-Redirect

        // Certificate for Signing
        // IMPORTANT: Replace "saml.pfx" with your actual certificate file and "password" with its password.
        // For production, load certificates securely from a store, not directly from file in wwwroot.
        private const string CertificateFileName = "saml.pfx";
        private const string CertificatePassword = "password"; 

        public void OnGet()
        {
            try
            {
                // 1. Generate SAML AuthnRequest XML
                XmlDocument samlRequest = CreateSamlAuthnRequest();

                // 2. Encrypt a hypothetical "sensitive" element using 3DES
                // IMPORTANT: This part is for demonstration of encryption on an element as requested.
                // It is highly unusual for an AuthnRequest to contain encrypted data.
                // SAML encryption (e.g., of NameID or Attributes) is typically done within the Assertion by the IdP.
                EncryptSensitiveElement(samlRequest, "SensitiveData", "This is some sensitive data that should be encrypted.");

                // 3. Sign the SAML AuthnRequest XML
                X509Certificate2 signingCert = LoadCertificate();
                SignSamlDocument(samlRequest, signingCert);

                SamlRequestXml = FormatXml(samlRequest);
            }
            catch (Exception ex)
            {
                ErrorMessage = $"An error occurred: {ex.Message}";
                SamlRequestXml = "Error generating SAML request.";
            }
        }

        private XmlDocument CreateSamlAuthnRequest()
        {
            XmlDocument doc = new XmlDocument();
            doc.PreserveWhitespace = true; // Preserve whitespace for proper signing/encryption

            // SAML Protocol Namespace
            string samlProtocolNs = "urn:oasis:names:tc:SAML:2.0:protocol";
            string samlAssertionNs = "urn:oasis:names:tc:SAML:2.0:assertion";
            string xsNs = "http://www.w3.org/2001/XMLSchema";
            string xsiNs = "http://www.w3.org/2001/XMLSchema-instance";

            // Create AuthnRequest element
            XmlElement authnRequest = doc.CreateElement("samlp", "AuthnRequest", samlProtocolNs);
            doc.AppendChild(authnRequest);

            authnRequest.SetAttribute("ID", "_" + Guid.NewGuid().ToString("N")); // SAML ID format
            authnRequest.SetAttribute("Version", "2.0");
            authnRequest.SetAttribute("IssueInstant", DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ss.fffZ"));
            authnRequest.SetAttribute("Destination", DestinationUrl);
            authnRequest.SetAttribute("AssertionConsumerServiceURL", AssertionConsumerServiceUrl);
            authnRequest.SetAttribute("ProtocolBinding", ProtocolBinding);
            authnRequest.SetAttribute("ForceAuthn", "false"); // Optional
            authnRequest.SetAttribute("IsPassive", "false");   // Optional

            // Add xmlns attributes
            authnRequest.SetAttribute("xmlns", samlProtocolNs);
            authnRequest.SetAttribute("xmlns:saml", samlAssertionNs);
            authnRequest.SetAttribute("xmlns:xs", xsNs);
            authnRequest.SetAttribute("xmlns:xsi", xsiNs);

            // Issuer element
            XmlElement issuer = doc.CreateElement("saml", "Issuer", samlAssertionNs);
            issuer.InnerText = IssuerEntityId;
            authnRequest.AppendChild(issuer);

            // NameIDPolicy element
            XmlElement nameIdPolicy = doc.CreateElement("samlp", "NameIDPolicy", samlProtocolNs);
            nameIdPolicy.SetAttribute("Format", "urn:oasis:names:tc:SAML:2.0:nameid-format:transient");
            nameIdPolicy.SetAttribute("AllowCreate", "true");
            authnRequest.AppendChild(nameIdPolicy);

            // RequestedAuthnContext (optional)
            XmlElement requestedAuthnContext = doc.CreateElement("samlp", "RequestedAuthnContext", samlProtocolNs);
            requestedAuthnContext.SetAttribute("Comparison", "exact");
            authnRequest.AppendChild(requestedAuthnContext);

            XmlElement authnContextClassRef = doc.CreateElement("saml", "AuthnContextClassRef", samlAssertionNs);
            authnContextClassRef.InnerText = "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport";
            requestedAuthnContext.AppendChild(authnContextClassRef);

            return doc;
        }

        private void EncryptSensitiveElement(XmlDocument doc, string elementName, string elementValue)
        {
            // Create a hypothetical element to encrypt
            // For demonstration, let's add it under AuthnRequest
            XmlElement authnRequest = doc.DocumentElement;
            if (authnRequest == null) return;

            XmlElement sensitiveElement = doc.CreateElement("Custom", elementName, authnRequest.NamespaceURI);
            sensitiveElement.InnerText = elementValue;
            authnRequest.AppendChild(sensitiveElement);

            // Use TripleDES for encryption as requested
            using (TripleDESCryptoServiceProvider tdes = new TripleDESCryptoServiceProvider())
            {
                tdes.GenerateKey();
                tdes.GenerateIV();
                tdes.Mode = CipherMode.CBC;
                tdes.Padding = PaddingMode.PKCS7;

                EncryptedXml encryptedXml = new EncryptedXml(doc);
                
                // Encrypt the element's content
                byte[] encryptedElementData = encryptedXml.EncryptData(sensitiveElement, tdes, false);

                EncryptedData edElement = new EncryptedData
                {
                    Type = EncryptedXml.XmlEncElementUrl,
                    Id = "_" + Guid.NewGuid().ToString("N")
                };

                // Add encryption method
                EncryptionMethod em = new EncryptionMethod(EncryptedXml.XmlEncTripleDESUrl);
                edElement.EncryptionMethod = em;

                // Add KeyInfo for the symmetric key (not typically done this way for AuthnRequest)
                // In real SAML assertion encryption, the symmetric key is encrypted using the recipient's public key
                // and then placed in KeyInfo. Here, we're demonstrating raw symmetric encryption.
                KeyInfo keyInfo = new KeyInfo();
                KeyInfoNode kn = new KeyInfoNode(doc.CreateTextNode("<!-- Symmetric key info would go here -->"));
                // For demonstration, we'll embed the raw key in a non-standard way or skip key transport.
                // For this example, we'll just demonstrate the EncryptedData structure.
                // To properly send the key, you would encrypt tdes.Key with the IdP's public key
                // and embed that in KeyInfo as an EncryptedKey.
                // This is beyond the scope of merely showing 3DES encryption on an element.
                // We will demonstrate the *encrypted data* part and structure.

                // Create a placeholder KeyInfo with no actual key for this simplified demo
                // A real scenario would use <EncryptedKey> with recipient's public key
                KeyInfoName kiName = new KeyInfoName();
                kiName.Value = "SymmetricKeyPlaceholder";
                keyInfo.AddClause(kiName);
                edElement.KeyInfo = keyInfo;

                CipherData cd = new CipherData();
                cd.CipherValue = encryptedElementData;
                edElement.CipherData = cd;

                // Replace the original element with the EncryptedData element
                EncryptedXml.ReplaceElement(sensitiveElement, edElement, false);
            }
        }

        private void SignSamlDocument(XmlDocument doc, X509Certificate2 certificate)
        {
            // Create a SignedXml object.
            SignedXml signedXml = new SignedXml(doc);

            // Add the key to the SignedXml document.
            signedXml.SigningKey = certificate.GetRSAPrivateKey();

            // Retrieve the ID of the root element (AuthnRequest)
            string referenceUri = "#" + doc.DocumentElement.GetAttribute("ID");

            // Create a Reference object for the document.
            Reference reference = new Reference();
            reference.Uri = referenceUri;

            // Add an XMLDsigExcC14NTransform to the reference to ensure consistent XML for signing
            XmlDsigExcC14NTransform c14nTransform = new XmlDsigExcC14NTransform();
            reference.AddTransform(c14nTransform);

            // Add the SHA1 digest method
            reference.DigestMethod = SignedXml.XmlDsigSHA1Url;

            // Add the Reference object to the SignedXml object.
            signedXml.AddReference(reference);

            // Add an RSAKeyValue KeyInfo (or X509Certificate KeyInfo) for the signing key.
            KeyInfo keyInfo = new KeyInfo();
            KeyInfoX509Data keyInfoData = new KeyInfoX509Data(certificate);
            keyInfo.AddClause(keyInfoData);
            signedXml.KeyInfo = keyInfo;

            // Set the signing method to RSA with SHA1
            signedXml.SignedInfo.SignatureMethod = SignedXml.XmlDsigRSASHA1Url;
            
            // Compute the signature.
            signedXml.ComputeSignature();

            // Get the XML representation of the signature and add it to the document.
            XmlElement xmlDigitalSignature = signedXml.GetXml();

            // Insert the signature just before the Issuer element (standard SAML practice)
            XmlNode issuerElement = doc.DocumentElement.SelectSingleNode("saml:Issuer", new XmlNamespaceManager(doc.NameTable)
            {
                { "saml", "urn:oasis:names:tc:SAML:2.0:assertion" }
            });

            if (issuerElement != null)
            {
                doc.DocumentElement.InsertBefore(xmlDigitalSignature, issuerElement);
            }
            else
            {
                // Fallback: append at the end if Issuer not found
                doc.DocumentElement.AppendChild(xmlDigitalSignature);
            }
        }

        private X509Certificate2 LoadCertificate()
        {
            // Load the certificate from the wwwroot/App_Data folder
            string certPath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "App_Data", CertificateFileName);

            if (!System.IO.File.Exists(certPath))
            {
                throw new FileNotFoundException($"Certificate file not found: {certPath}. Please ensure '{CertificateFileName}' is in 'wwwroot/App_Data'.");
            }

            try
            {
                X509Certificate2 certificate = new X509Certificate2(certPath, CertificatePassword, X509KeyStorageFlags.Exportable);
                // Ensure the private key is available
                if (!certificate.HasPrivateKey)
                {
                    throw new CryptographicException("Certificate does not have a private key for signing.");
                }
                return certificate;
            }
            catch (CryptographicException ex)
            {
                if (ex.Message.Contains("The specified network password is not correct"))
                {
                     throw new CryptographicException($"Incorrect password for certificate '{CertificateFileName}'. {ex.Message}");
                }
                throw;
            }
        }

        private string FormatXml(XmlDocument doc)
        {
            using (StringWriter sw = new StringWriter())
            using (XmlTextWriter xw = new XmlTextWriter(sw) { Formatting = Formatting.Indented })
            {
                doc.Save(xw);
                return sw.ToString();
            }
        }
    }
}
